import React, { useState, useEffect } from 'react';
import AOS from 'aos';
import 'aos/dist/aos.css';

// Component Imports
import Hero from './components/sections/Hero';
import FlowerPetals from './components/animations/FlowerPetals';
import Countdown from './components/ui/Countdown';
import Timeline from './components/sections/Timeline';
import Gallery from './components/sections/Gallery';
import RSVPForm from './components/sections/RSVPForm';
import InvitationQR from './components/ui/InvitationQR';
import MusicPlayer from './components/ui/MusicPlayer';
import Navbar from './components/ui/Navbar'; // New
import ThreeRings from './components/animations/ThreeRings'; // New

function App() {
  const [submittedData, setSubmittedData] = useState(null);

  useEffect(() => {
    try {
      AOS.init({ 
        duration: 1000, 
        once: true,
        offset: 50,
        disable: window.innerWidth < 768 
      });
      AOS.refresh();
    } catch (e) {
      console.error("AOS init error:", e);
    }
  }, []);

  return (
    <div className="bg-[#FAF9F6] min-h-screen selection:bg-luxury-gold selection:text-white">
      {/* 1. Fixed Floating Elements */}
      <Navbar />
      <MusicPlayer />
      <FlowerPetals />
      
      {/* 2. Cinematic 3D Hero Section */}
      <section id="home" className="relative h-screen flex flex-col items-center justify-center overflow-hidden">
        <div className="absolute inset-0 z-0">
           <ThreeRings />
        </div>
        <div className="text-center z-10 pointer-events-none">
          <h1 className="text-6xl md:text-9xl font-serif text-luxury-gold italic drop-shadow-sm" data-aos="zoom-in">
            Arjun & Diya
          </h1>
          <p className="text-luxury-dark tracking-[0.6em] uppercase text-[10px] md:text-xs mt-6 opacity-70" data-aos="fade-up" data-aos-delay="500">
            Together with their families invite you
          </p>
        </div>
      </section>
      
      {/* 3. Wedding Countdown */}
      <div id="countdown" className="py-16 bg-white shadow-inner relative z-10">
        <Countdown targetDate="2026-12-04" />
      </div>

      {/* 4. Love Story Timeline */}
      <section id="story" className="py-24 max-w-5xl mx-auto px-6">
        <div className="text-center mb-16" data-aos="fade-up">
          <h2 className="font-serif text-5xl italic text-gray-800">Our Story</h2>
          <div className="h-px w-24 bg-luxury-gold mx-auto mt-4"></div>
        </div>
        <Timeline />
      </section>

      {/* 5. Modern Photo Gallery */}
      <section id="gallery" className="py-12 bg-white">
        <Gallery />
      </section>

      {/* 6. Premium RSVP Section */}
      <section id="rsvp" className="py-24 bg-[#1A1A1B] text-white overflow-hidden">
        {!submittedData ? (
          <div data-aos="fade-up">
            <RSVPForm onSubmissionSuccess={(data) => setSubmittedData(data)} />
          </div>
        ) : (
          <div className="flex flex-col items-center py-10" data-aos="zoom-out">
             <h2 className="font-serif text-4xl mb-4 italic">You're on the list!</h2>
             <p className="text-luxury-gold tracking-widest text-xs mb-10 uppercase">Save your digital invite</p>
             <InvitationQR guestName={submittedData.name} />
          </div>
        )}
      </section>

      {/* 7. Footer */}
      <footer className="py-16 text-center bg-[#FAF9F6]">
        <div className="font-serif italic text-3xl text-luxury-dark mb-4">A & D</div>
        <p className="text-gray-400 uppercase tracking-[0.4em] text-[9px]">
          Designed for Eternal Love — 2026
        </p>
      </footer>
    </div>
  );
}

export default App;
